// // This module implements a 16-bit shift register with parallel load and terminal count output.
// It takes a clock signal (clk), a reset signal (rst), a load signal (load), and a 16-bit parallel load input (load_val).
// The counter should reset to 0 when the reset signal is low. If the load signal is low, the counter should load the value from load_val.
// The terminal count output (tc) should go high when the least significant bit is 1.
module shift_register16bit_tc (
	input clk,
	input rst,
	input load,
	input [15:0] load_val,
	output reg [15:0] q,
	output tc);

	always @(posedge clk or posedge rst) begin
		if (rst)
			q <= 16'b0000000000000000;
		else if (load)
			q <= load_val;
		else
			q <= {q[14:0], 1'b0};
	end

	assign tc = q[15];

endmodule

